fixes.origin:
location = os.path.join(BASE_STORAGE, identifier)
with open(location, "r", encoding="utf-8") as reader:
    return reader.readline()

fixes.replacement:
candidate = os.path.abspath(os.path.join(BASE_STORAGE, identifier))
base = os.path.abspath(BASE_STORAGE)
if os.path.commonpath([base, candidate]) != base:
    raise ValueError("invalid path")
with open(candidate, "r", encoding="utf-8") as reader:
    return reader.readline()
